class Solution:
    def pyramidTransition(self, bottom, allowed):
        from collections import defaultdict
        tops = defaultdict(list)
        for p in allowed:
            tops[p[:2]].append(p[2])
        def build(row):
            if len(row) == 1:
                return True
            pairs = [tops[row[i:i+2]] for i in range(len(row) - 1)]
            import itertools
            for combo in itertools.product(*pairs):
                if build(''.join(combo)):
                    return True
            return False
        return build(bottom)

