class Solution:
    def pyramidTransition(self, bottom, allowed):
        from collections import defaultdict
        tops = defaultdict(list)
        for p in allowed:
            tops[p[:2]].append(p[2])
        memo = set()
        def solve(row):
            if len(row) == 1:
                return True
            if row in memo:
                return False
            def nxt(i, cur):
                if i == len(row) - 1:
                    return solve(cur)
                for t in tops.get(row[i:i+2], ()):
                    if nxt(i + 1, cur + t):
                        return True
                return False
            ok = nxt(0, '')
            if not ok:
                memo.add(row)
            return ok
        return solve(bottom)

