var pyramidTransition = function(bottom, allowed) {
    const tops = {};
    for (const p of allowed) {
        const key = p.slice(0, 2);
        if (!tops[key]) tops[key] = [];
        tops[key].push(p[2]);
    }
    const memo = new Set();
    function solve(row) {
        if (row.length === 1) return true;
        if (memo.has(row)) return false;
        function nxt(i, cur) {
            if (i === row.length - 1) return solve(cur);
            const opts = tops[row.slice(i, i + 2)] || [];
            for (const t of opts) {
                if (nxt(i + 1, cur + t)) return true;
            }
            return false;
        }
        const ok = nxt(0, '');
        if (!ok) memo.add(row);
        return ok;
    }
    return solve(bottom);
};
